+func TestDCGAvailabilityWithFakeTool(t *testing.T) {
+	cleanup := withFakeTools(t)
+	defer cleanup()
+
+	adapter := NewDCGAdapter()
+	adapter.InvalidateAvailabilityCache()
+
+	ctx := context.Background()
+	availability, err := adapter.GetAvailability(ctx)
+	if err != nil {
